import{_ as o,o as t,c as d,ae as a}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"터미널 환경 최적화","description":"Claude Code에서 최상의 경험을 위한 터미널 설정 방법","frontmatter":{"title":"터미널 환경 최적화","description":"Claude Code에서 최상의 경험을 위한 터미널 설정 방법"},"headers":[],"relativePath":"terminal-config.md","filePath":"terminal-config.md","lastUpdated":1776205703000}'),c={name:"terminal-config.md"};function i(l,e,n,r,s,p){return t(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="터미널-환경-최적화" tabindex="-1">터미널 환경 최적화 <a class="header-anchor" href="#터미널-환경-최적화" aria-label="Permalink to &quot;터미널 환경 최적화&quot;">​</a></h1><blockquote><p>Claude Code는 터미널이 올바르게 설정되어 있을 때 가장 잘 작동합니다. 아래 가이드라인을 따라 환경을 최적화하세요.</p></blockquote><h3 id="테마-및-외관" tabindex="-1">테마 및 외관 <a class="header-anchor" href="#테마-및-외관" aria-label="Permalink to &quot;테마 및 외관&quot;">​</a></h3><p>Claude는 터미널의 테마를 직접 제어할 수 없습니다. 테마는 터미널 애플리케이션에서 설정합니다. <code>/config</code> 명령어를 통해 언제든지 Claude Code의 테마를 터미널에 맞게 변경할 수 있습니다.</p><p>Claude Code 인터페이스 자체를 추가로 커스터마이징하려면 <a href="/claude-code-docs-ko/statusline.html">사용자 정의 상태 표시줄</a>을 설정하여 현재 모델, 작업 디렉토리, git 브랜치 등의 상황별 정보를 터미널 하단에 표시할 수 있습니다.</p><h3 id="줄-바꿈" tabindex="-1">줄 바꿈 <a class="header-anchor" href="#줄-바꿈" aria-label="Permalink to &quot;줄 바꿈&quot;">​</a></h3><p>Claude Code에서 줄 바꿈을 입력하는 방법은 여러 가지가 있습니다:</p><ul><li><strong>빠른 이스케이프</strong>: <code>\\</code> 를 입력한 후 Enter를 눌러 새 줄 삽입</li><li><strong>Ctrl+J</strong>: 라인 피드 문자를 전송하며, 별도 설정 없이 모든 터미널에서 줄 바꿈으로 작동</li><li><strong>Shift+Enter</strong>: iTerm2, WezTerm, Ghostty, Kitty에서 기본 지원</li><li><strong>키보드 단축키</strong>: 다른 터미널에서 새 줄을 삽입하는 키 바인딩 설정 가능</li></ul><h4 id="terminal-setup으로-shift-enter-설정하기" tabindex="-1">/terminal-setup으로 Shift+Enter 설정하기 <a class="header-anchor" href="#terminal-setup으로-shift-enter-설정하기" aria-label="Permalink to &quot;/terminal-setup으로 Shift+Enter 설정하기&quot;">​</a></h4><p>Claude Code 내에서 <code>/terminal-setup</code>을 실행하면 VS Code, Alacritty, Zed, Warp에서 Shift+Enter를 자동으로 설정합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><code>/terminal-setup</code> 명령어는 수동 설정이 필요한 터미널에서만 표시됩니다. iTerm2, WezTerm, Ghostty, Kitty를 사용 중이라면 Shift+Enter가 기본적으로 작동하므로 이 명령어가 나타나지 않습니다.</p></div><h4 id="tmux에서-shift-enter-설정하기" tabindex="-1">tmux에서 Shift+Enter 설정하기 <a class="header-anchor" href="#tmux에서-shift-enter-설정하기" aria-label="Permalink to &quot;tmux에서 Shift+Enter 설정하기&quot;">​</a></h4><p>tmux 내부에서는 확장 키 보고(extended key reporting)가 활성화되지 않으면 <code>Shift+Enter</code>가 새 줄 삽입 대신 제출로 작동합니다. <code>~/.tmux.conf</code>에 다음 줄을 추가하고 <code>tmux source-file ~/.tmux.conf</code>를 실행하여 설정을 다시 불러오세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set -s extended-keys on</span></span>
<span class="line"><span>set -as terminal-features &#39;xterm*:extkeys&#39;</span></span></code></pre></div><p>Claude Code는 시작 시 확장 키를 요청하지만, <code>extended-keys</code>가 <code>on</code>으로 설정되지 않으면 tmux가 이 요청을 무시합니다. <code>terminal-features</code> 줄은 외부 터미널이 해당 시퀀스를 전송할 수 있음을 tmux에 알려줍니다.</p><h4 id="macos에서-option-enter-설정하기" tabindex="-1">macOS에서 Option+Enter 설정하기 <a class="header-anchor" href="#macos에서-option-enter-설정하기" aria-label="Permalink to &quot;macOS에서 Option+Enter 설정하기&quot;">​</a></h4><p>macOS에서는 Option-as-Meta 설정을 활성화한 후 Terminal.app, iTerm2, VS Code 터미널에서 Option+Enter를 줄 바꿈 키 바인딩으로 사용할 수 있습니다.</p><p><strong>Terminal.app</strong></p><ol><li>설정 → 프로파일 → 키보드 열기</li><li>&quot;Use Option as Meta Key&quot; 체크</li></ol><p><strong>iTerm2</strong></p><ol><li>설정 → 프로파일 → Keys 열기</li><li>General에서 Left/Right Option key를 &quot;Esc+&quot;로 설정</li></ol><p><strong>VS Code</strong></p><p>VS Code 설정에서 <code>&quot;terminal.integrated.macOptionIsMeta&quot;: true</code>로 설정합니다.</p><h3 id="알림-설정" tabindex="-1">알림 설정 <a class="header-anchor" href="#알림-설정" aria-label="Permalink to &quot;알림 설정&quot;">​</a></h3><p>Claude가 작업을 완료하고 입력을 기다릴 때 알림 이벤트가 발생합니다. 이 이벤트를 터미널을 통해 데스크톱 알림으로 표시하거나 <a href="/claude-code-docs-ko/hooks.html#notification">알림 훅</a>으로 사용자 지정 동작을 실행할 수 있습니다.</p><h4 id="터미널-알림" tabindex="-1">터미널 알림 <a class="header-anchor" href="#터미널-알림" aria-label="Permalink to &quot;터미널 알림&quot;">​</a></h4><p>Kitty와 Ghostty는 별도 설정 없이 데스크톱 알림을 지원합니다. iTerm 2는 다음과 같이 설정해야 합니다:</p><ol><li>iTerm 2 설정 → 프로파일 → Terminal 열기</li><li>&quot;Notification Center Alerts&quot; 활성화</li><li>&quot;Filter Alerts&quot;를 클릭하고 &quot;Send escape sequence-generated alerts&quot; 체크</li></ol><p>알림이 표시되지 않는 경우, OS 설정에서 터미널 앱의 알림 권한이 허용되어 있는지 확인하세요.</p><p>tmux 내에서 Claude Code를 실행할 때, 알림과 <a href="/claude-code-docs-ko/settings.html#global-config-settings">터미널 진행 표시줄</a>이 iTerm2, Kitty, Ghostty 등의 외부 터미널에 전달되려면 tmux 설정에서 passthrough를 활성화해야 합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set -g allow-passthrough on</span></span></code></pre></div><p>이 설정이 없으면 tmux가 이스케이프 시퀀스를 가로채어 터미널 애플리케이션에 전달되지 않습니다.</p><p>기본 macOS Terminal을 포함한 다른 터미널은 네이티브 알림을 지원하지 않습니다. 대신 <a href="/claude-code-docs-ko/hooks.html#notification">알림 훅</a>을 사용하세요.</p><h4 id="알림-훅" tabindex="-1">알림 훅 <a class="header-anchor" href="#알림-훅" aria-label="Permalink to &quot;알림 훅&quot;">​</a></h4><p>알림이 발생할 때 소리 재생이나 메시지 전송과 같은 사용자 지정 동작을 추가하려면 <a href="/claude-code-docs-ko/hooks.html#notification">알림 훅</a>을 설정하세요. 훅은 터미널 알림과 함께 실행되며, 대체 수단이 아닙니다.</p><h3 id="화면-깜박임-및-메모리-사용-줄이기" tabindex="-1">화면 깜박임 및 메모리 사용 줄이기 <a class="header-anchor" href="#화면-깜박임-및-메모리-사용-줄이기" aria-label="Permalink to &quot;화면 깜박임 및 메모리 사용 줄이기&quot;">​</a></h3><p>긴 세션 중에 화면이 깜박이거나 Claude가 작업하는 동안 터미널 스크롤 위치가 상단으로 이동하는 경우, <a href="/claude-code-docs-ko/fullscreen.html">전체 화면 렌더링</a>을 시도해 보세요. 이 방식은 메모리를 일정하게 유지하고 마우스 지원을 추가하는 별도 렌더링 경로를 사용합니다. <code>CLAUDE_CODE_NO_FLICKER=1</code>로 활성화할 수 있습니다.</p><h3 id="대용량-입력-처리" tabindex="-1">대용량 입력 처리 <a class="header-anchor" href="#대용량-입력-처리" aria-label="Permalink to &quot;대용량 입력 처리&quot;">​</a></h3><p>방대한 코드나 긴 지시사항을 다룰 때:</p><ul><li><strong>직접 붙여넣기 지양</strong>: Claude Code는 매우 긴 붙여넣기 내용을 처리하는 데 어려움을 겪을 수 있습니다</li><li><strong>파일 기반 워크플로우 사용</strong>: 내용을 파일에 작성하고 Claude에게 해당 파일을 읽도록 요청하세요</li><li><strong>VS Code 제한 사항 인지</strong>: VS Code 터미널은 긴 붙여넣기를 잘라내는 경향이 있습니다</li></ul><h3 id="vim-모드" tabindex="-1">Vim 모드 <a class="header-anchor" href="#vim-모드" aria-label="Permalink to &quot;Vim 모드&quot;">​</a></h3><p>Claude Code는 <code>/config</code> → Editor mode를 통해 활성화할 수 있는 Vim 키 바인딩의 일부를 지원합니다. 설정 파일에서 직접 모드를 설정하려면 <code>~/.claude.json</code>의 <a href="/claude-code-docs-ko/settings.html#global-config-settings"><code>editorMode</code></a> 전역 설정 키를 <code>&quot;vim&quot;</code>으로 설정하세요.</p><p>지원되는 기능은 다음과 같습니다:</p><ul><li>모드 전환: <code>Esc</code> (NORMAL), <code>i</code>/<code>I</code>, <code>a</code>/<code>A</code>, <code>o</code>/<code>O</code> (INSERT)</li><li>탐색: <code>h</code>/<code>j</code>/<code>k</code>/<code>l</code>, <code>w</code>/<code>e</code>/<code>b</code>, <code>0</code>/<code>$</code>/<code>^</code>, <code>gg</code>/<code>G</code>, <code>f</code>/<code>F</code>/<code>t</code>/<code>T</code> (<code>;</code>/<code>,</code> 반복 포함)</li><li>편집: <code>x</code>, <code>dw</code>/<code>de</code>/<code>db</code>/<code>dd</code>/<code>D</code>, <code>cw</code>/<code>ce</code>/<code>cb</code>/<code>cc</code>/<code>C</code>, <code>.</code> (반복)</li><li>Yank/붙여넣기: <code>yy</code>/<code>Y</code>, <code>yw</code>/<code>ye</code>/<code>yb</code>, <code>p</code>/<code>P</code></li><li>텍스트 객체: <code>iw</code>/<code>aw</code>, <code>iW</code>/<code>aW</code>, <code>i&quot;</code>/<code>a&quot;</code>, <code>i&#39;</code>/<code>a&#39;</code>, <code>i(</code>/<code>a(</code>, <code>i[</code>/<code>a[</code>, <code>i{</code>/<code>a{</code></li><li>들여쓰기: <code>&gt;&gt;</code>/<code>&lt;&lt;</code></li><li>줄 조작: <code>J</code> (줄 합치기)</li></ul><p>전체 참고 사항은 <a href="/claude-code-docs-ko/interactive-mode.html#vim-editor-mode">대화형 모드</a>를 참조하세요.</p>`,45)])])}const m=o(c,[["render",i]]);export{u as __pageData,m as default};
